import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.*;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.client.RestTemplate;

import javax.servlet.http.HttpServletResponse;
import java.util.Map;

@SpringBootApplication
@RestController
public class WebhookHandler {

    @Value("${server.ssl.key-store}")
    private String keyStore;

    @Value("${server.ssl.key-store-password}")
    private String keyStorePassword;

    @Value("${server.ssl.key-alias}")
    private String keyAlias;

    @Value("${server.port}")
    private int port;

    private final RestTemplate restTemplate = new RestTemplate();

    public static void main(String[] args) {
        SpringApplication.run(WebhookHandler.class, args);
    }

    @PostMapping("/webhooks")
    public ResponseEntity<String> handleWebhook(@RequestHeader Map<String, String> headers, HttpServletResponse response, @RequestBody String requestBody) {
        if (!headers.containsKey("Authorization")) {
            return new ResponseEntity<>("Unauthorized", HttpStatus.UNAUTHORIZED);
        }

        String[] auth = headers.get("Authorization").split(" ");
        if (auth.length != 2 || !"Basic".equalsIgnoreCase(auth[0])) {
            return new ResponseEntity<>("Invalid Authorization header", HttpStatus.BAD_REQUEST);
        }

        String credentials = new String(Base64.getDecoder().decode(auth[1]));
        String username = credentials.split(":")[0];
        String password = credentials.split(":")[1];

        if (!"valid-user".equals(username) || !"valid-password".equals(password)) {
            return new ResponseEntity<>("Invalid username or password", HttpStatus.UNAUTHORIZED);
        }

        String url = requestBody;
        try {
            HttpHeaders httpHeaders = new HttpHeaders();
            httpHeaders.setContentType(MediaType.TEXT_HTML);
            ResponseEntity<String> responseEntity = restTemplate.exchange(url, HttpMethod.GET, new HttpEntity<>(httpHeaders), String.class);
            return responseEntity;
        } catch (Exception e) {
            return new ResponseEntity<>("Error fetching content from URL: " + url, HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }
}